item.content:encoded:
.wpcf7-form input[type="text"], 
.wpcf7-form input[type="email"], 
.wpcf7-form input[type="url"], 
.wpcf7-form input[type="password"], 
.wpcf7-form input[type="search"],
.wpcf7-form input[type="number"], 
.wpcf7-form input[type="tel"], 
.wpcf7-form textarea {
    color: #1f252b;
    width: 100%;
    padding: 12px 16px;
        border-radius: 10px;
    border: 1px solid #ccc;
	 font-family: "DM Sans", Sans-serif !important;
}
.elementor-size-sm:hover{cursor:pointer !important;}
.wpcf7-form p {
    margin: 0 0 10px;
}
.wpcf7-text:focus, 
.wpcf7-textarea:focus {
    outline: 1px solid rgba(84, 222, 197, 0.9);
    outline-offset: 0;
}
div.wpcf7-mail-sent-ok {
    border: 0;
    background: #5471de;
    color: #fff;
    padding: 18px;
}
div.wpcf7-acceptance-missing,
div.wpcf7-validation-errors {
    border: 0;
    background: #f9443b;
    color: #fff;
    padding: 18px;
}
span.wpcf7-not-valid-tip {
    color: #f9443b;
}
#sgpb-popup-dialog-main-div{margin-top:5px !important;}
.wpcf7 form .wpcf7-response-output {
    margin: 0em 0.5em 1em !important;
}
/* 
** Button Styles 
*/
.wpcf7-form .button {
    background-color: #6b52d1 !important;
    border: 10px !important;
    color: #fff !important;
    border-radius: 10px !important;
    font-weight: 700;
    text-align: center;
    text-transform: uppercase;
    margin-bottom: 15px;
    width: auto;
    padding: 15px 42px;
    letter-spacing: 2px;
    font-size: 14px;
	    font-family: "DM Sans", Sans-serif !important;
}
.wpcf7-form .button:hover {
    cursor: pointer;
    box-shadow: 0px 7px 16px -7px rgba(0, 0, 0, 0.4);
    border: 0;
}
.sgpb-popup-close-button-1{
    right: 16px !important;bottom: 0px;    top: 17px !important;}

.elementor-21 .elementor-element.elementor-element-4c2b7f3 .elementskit-navbar-nav .elementskit-submenu-panel
{
	border-radius: 10px;
	min-width: 170px;
}

.ekit-wid-con .elementskit-post-image-card .elementskit-entry-header .elementskit-entry-thumb>img
{
	border-radius: 10px;
}

.elementor-1379 .elementor-element.elementor-element-060e2b5 .elementskit-blog-block-post, .elementor-1379 .elementor-element.elementor-element-060e2b5 .elementskit-post-image-card, .elementor-1379 .elementor-element.elementor-element-060e2b5 .elementskit-post-card
{
	margin: 0px;
}

