[{"id":"4394cd0","elType":"container","settings":{"flex_direction":"row","flex_gap":{"unit":"px","size":0,"column":"0","row":"0"},"background_background":"classic","background_image":{"url":"https://visble.ai/wp-content/uploads/2025/05/hero-bg.webp","id":33,"size":"","alt":"","source":"library"},"flex_wrap":"wrap","background_overlay_background":"classic","background_overlay_image":{"url":"https://visble.ai/wp-content/uploads/2025/05/hero-after.png","id":41,"size":"","alt":"","source":"library"},"background_overlay_position":"bottom left","background_overlay_repeat":"repeat-x","background_overlay_opacity":{"unit":"px","size":1,"sizes":[]},"padding":{"unit":"px","top":"200","right":"20","bottom":"145","left":"20","isLinked":false},"padding_mobile":{"unit":"px","top":"150","right":"20","bottom":"100","left":"20","isLinked":false},"background_position":"top center","background_repeat":"no-repeat","background_size":"cover"},"elements":[{"id":"ee9770e","elType":"widget","settings":{"html":"<style>
 @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;600;700&display=swap');

 .llm-wrapper {
 max-width: 900px;
 margin: 60px auto;
 padding: 50px;
 border-radius: 20px;
 box-shadow: 0 8px 30px rgba(0, 0, 0, 0.07);
 background: #fff;
 text-align: center;
 font-family: 'Inter', 'Segoe UI', sans-serif;
 color: #000;
 }

 .llm-title {
 font-size: 38px;
 font-weight: 700;
 margin-bottom: 12px;
 }

 .llm-subtitle {
 font-size: 16px;
 color: #555;
 margin-bottom: 32px;
 }

 .llm-input-container {
 display: flex;
 height: 56px; /* ✅ fixed height for alignment */
 border: 2px solid #8c52ff;
 border-radius: 14px;
 overflow: hidden;
 transition: border-color 0.3s;
 }

 .llm-input-container input {
 flex: 1;
 padding: 0 18px;
 font-size: 16px;
 border: none;
 outline: none;
 }

 .llm-input-container button {
 background: #8c52ff;
 color: #fff;
 border: 2px solid #723ee3;
 border-left: none;
 padding: 0 28px;
 font-size: 16px;
 cursor: pointer;
 box-sizing: border-box;
 height: 100%; /* ✅ makes button match input height */
 transition: background 0.3s ease, border-color 0.3s ease, color 0.3s ease;
 }

 .llm-input-container button:hover {
 background: #6e3de0;
 border-color: #5c31c4;
 color: #fff;
 }

 .llm-alert {
 background: #fff0f0;
 color: #b30000;
 border: 1px solid #f5c0c0;
 padding: 14px;
 margin-top: 24px;
 border-radius: 10px;
 font-size: 14px;
 display: none;
 }

 .llm-alert::before {
 content: "⚠️";
 margin-right: 8px;
 }

 .llm-loading {
 background: #f7f7f7;
 color: #444;
 padding: 14px;
 margin-top: 24px;
 border-radius: 10px;
 font-size: 15px;
 display: none;
 align-items: center;
 justify-content: center;
 gap: 8px;
 }

 .llm-loading::before {
 content: "";
 width: 14px;
 height: 14px;
 border-radius: 50%;
 border: 2px solid #8c52ff;
 border-top-color: transparent;
 animation: spin 1s linear infinite;
 display: inline-block;
 }

 @keyframes spin {
 to {
 transform: rotate(360deg);
 }
 }

 .llm-output {
 background: #f9f9f9;
 border: 1px solid #ddd;
 padding: 20px;
 margin-top: 24px;
 border-radius: 12px;
 font-family: monospace;
 white-space: pre-wrap;
 text-align: left;
 font-size: 14px;
 display: none;
 }
</style>

<div class="llm-wrapper">
 <div class="llm-title">LLMs.txt Generator</div>
 <div class="llm-subtitle">Future-proof your SEO by controlling how AI models crawl your site.</div>

 <div class="llm-input-container">
 <input type="text" id="llm-url" placeholder="https://example.com/" />
 <button onclick="generateLLMTxt()">Generate Now</button>
 </div>

 <div id="llm-alert" class="llm-alert">
 Only 5 generations allowed on the free tool. Please book a call with us for more.
 </div>

 <div id="llm-loading" class="llm-loading">
 <span>Generating llms.txt for you...</span>
 </div>

 <div id="llm-output" class="llm-output"></div>
</div>

<script>
 function generateLLMTxt() {
 const maxTries = 5;
 const tries = parseInt(localStorage.getItem("llmTries") || "0");

 const alertBox = document.getElementById("llm-alert");
 const loadingBox = document.getElementById("llm-loading");
 const outputBox = document.getElementById("llm-output");

 alertBox.style.display = "none";
 loadingBox.style.display = "none";
 outputBox.style.display = "none";

 if (tries >= maxTries) {
 alertBox.style.display = "block";
 return;
 }

 const url = document.getElementById("llm-url").value.trim();
 if (!url) {
 outputBox.innerText = "Please enter a valid URL.";
 outputBox.style.display = "block";
 return;
 }

 loadingBox.style.display = "flex";

 fetch(`https://62dp1b284h.execute-api.us-east-1.amazonaws.com/llm_txt/generate?url=${encodeURIComponent(url)}&max_links=20`)
 .then((res) => res.json())
 .then((data) => {
 loadingBox.style.display = "none";
 outputBox.style.display = "block";

 if (data.success) {
 outputBox.innerText = data.content;
 localStorage.setItem("llmTries", (tries + 1).toString());
 } else {
 outputBox.innerText = "❌ Failed to generate. Please try again later.";
 }
 })
 .catch((err) => {
 loadingBox.style.display = "none";
 outputBox.style.display = "block";
 outputBox.innerText = "❌ Error calling the API.";
 console.error(err);
 });
 }
</script>
