"elements":[],"widgetType":"elementskit-blog-posts"},{"id":"521ace3","elType":"widget","settings":{"html":"<div class="blog-pattern-left"></div>
<div class="blog-pattern-right"></div>

<style>
.blog-pattern-left,
.blog-pattern-right {
 position: fixed;
 top: 0;
 height: 100vh;
 width: 45px;
 pointer-events: none;
 z-index: 1;
 background: repeating-linear-gradient(
 135deg,
 #ffffff,
 #ffffff 1px,
 transparent 1px,
 transparent 10px
 );
 border-left: 1px solid #ffffff;
 border-right: 1px solid #ffffff;
 opacity: 0.15;
}

.blog-pattern-left {
 left: 0;
}

.blog-pattern-right {
 right: 0;
}

.blog-pattern-left::before,
.blog-pattern-left::after,
.blog-pattern-right::before,
.blog-pattern-right::after {
 content: '';
 position: absolute;
 width: 1px;
 height: 10px;
 background-color: #ffffff;
 opacity: 0.15;
}

/* Left side cap lines */
.blog-pattern-left::before {
 top: 0;
 left: 0;
}
.blog-pattern-left::after {
 bottom: 0;
 left: 0;
}

/* Right side cap lines */
.blog-pattern-right::before {
 top: 0;
 right: 0;
}
.blog-pattern-right::after {
 bottom: 0;
 right: 0;
}
</style>
"},"elements":[],"widgetType":"html"}],"isInner":false}]

